export const getMatchupWinProbForRound = (
  teamAName: string,
  teamBName: string,
  round: Round
): number | null => {
  const a = canonicalTeamNameForMatchup(teamAName);
  const b = canonicalTeamNameForMatchup(teamBName);
  if (!a || !b || a === b) return null;
  const key = `${a}|${b}|${round}`;
  const prob = MATCHUP_PROB_BY_STAGE[key];
  return Number.isFinite(prob) ? prob : null;
};
